+    // loop: sum += i; i -= 1; if i != 0 goto loop
+    // return sum
+    let program = Program {
+        constants: vec![Value::Int(0), Value::Int(5), Value::Int(1)],
+        property_pool: Vec::new(),
+        instructions: vec![
+            // r0 = sum = 0
