+                dst: r(0),
+                const_index: 0,
+            },
+            // r1 = i = 5
+            Instruction::LoadConst {
+                dst: r(1),
+                const_index: 1,
+            },
+            // r2 = 1
+            Instruction::LoadConst {
+                dst: r(2),
+                const_index: 2,
+            },
+            // loop: sum += i
+            Instruction::Add {
+                dst: r(0),
+                lhs: r(0),
+                rhs: r(1),
+            },
+            // i -= 1
